############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "PGlateximage.pl", "parserAssignment.pl", "contextFraction.pl", "Pd.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ Context("Fraction")->variables->are(A => 'Real', b => 'Real', h => 'Real'); parser::Assignment->Allow; $ans = Assignment("b = (2A)/h");
$introduction_image_1 = createLaTeXImage(); $introduction_image_1->addToPreamble(latexImagePreamble()); $introduction_image_1->BEGIN_LATEX_IMAGE \begin{tikzpicture} \draw[fill=firstcolor!20!white,thick] (0,0) -| (3,2) -- cycle; \node at (1.5,0) [below] {base \(b\)}; \draw [rightangle] (3,0.2) -| (2.8,0); \node at (3,1) [right] {height \(h\)}; \node at (2,1) [below] {area \(A\)}; \end{tikzpicture}
END_LATEX_IMAGE
############################################################ # Body ############################################################
BEGIN_PGML The area of a triangle is given by [`A=\frac12bh\text{,}`] where [`b`] is the base width, and [`h`] is the height.
>> [@image(insertGraph($introduction_image_1), width=>198)@]* <<
Solve the equation [`A=\frac12bh`] for [`b\text{.}`]
[_]{$ans}{16}
END_PGML
############################################################ # Solution ############################################################
BEGIN_PGML_SOLUTION We need to keep our focus on [`b`] and take algebra steps that bring us closer to isolating [`b\text{.}`]
[```\newcommand{\amp}{&} \begin{aligned} A \amp= \frac12bh\\ 2A \amp= bh\\ \frac{2A}{h} \amp= b\\ b \amp= \frac{2A}{h} \end{aligned} ```]
END_PGML_SOLUTION
